+fn is_valid_robot_error_code(s: &str) -> bool {
+    let Some(rest) = s.strip_prefix("robot.") else {
+        return false;
+    };
+
+    let mut saw_segment = false;
+    for segment in rest.split('.') {
+        if segment.is_empty()
+            || !segment
+                .bytes()
+                .all(|b| b.is_ascii_lowercase() || b.is_ascii_digit() || b == b'_')
+        {
+            return false;
+        }
+        saw_segment = true;
+    }
+
+    saw_segment
+}
